import sys

def solve():
    it = iter(sys.stdin.read().split())
    try:
        n = int(next(it))
    except StopIteration:
        return
    # define node class
    class Node:
        __slots__ = ('val','next')
        def __init__(self, val, nxt=None):
            self.val = val
            self.next = nxt
    head = None  # top of stack
    out_lines = []
    for _ in range(n):
        op = next(it)
        if op == 'push':
            x = int(next(it))
            head = Node(x, head)
        elif op == 'pop':
            if head is None:
                out_lines.append('-1')
            else:
                out_lines.append(str(head.val))
                head = head.next
        elif op == 'top':
            out_lines.append(str(head.val) if head is not None else '-1')
        elif op == 'isEmpty':
            out_lines.append('true' if head is None else 'false')
        else:
            # unknown operation, ignore
            pass
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

