#include <bits/stdc++.h>
using namespace std;
struct Node {
    long long val;
    Node* next;
    Node(long long v, Node* n): val(v), next(n) {}
};
int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    if(!(cin>>n)) return 0;
    Node* head = nullptr; // top of stack
    vector<string> out;
    for(int i=0;i<n;++i){
        string op;cin>>op;
        if(op=="push"){
            long long x;cin>>x;
            head = new Node(x, head);
        }else if(op=="pop"){
            if(!head){
                out.push_back("-1");
            }else{
                out.push_back(to_string(head->val));
                Node* tmp=head;
                head=head->next;
                delete tmp;
            }
        }else if(op=="top"){
            out.push_back(head? to_string(head->val) : string("-1"));
        }else if(op=="isEmpty"){
            out.push_back(head? "false" : "true");
        }
    }
    for(size_t i=0;i<out.size();++i){
        if(i) cout<<'\n';
        cout<<out[i];
    }
    return 0;
}
